

App.Modules.Security = class extends Colibri.Modules.Module {

    /** @constructor */
    constructor() {
        super('Security');
    }



    InitializeModule() {
        super.InitializeModule();

        this.userData = {};

        this._loginForm = null;

        this._store = App.Store.AddChild('app.security', {}, this);
        this._store.AddPathLoader('security.roles', () => this.Roles(true));
        this._store.AddPathLoader('security.users', () => this.Users(true));
        this._store.AddHandler('StoreLoaderCrushed', (event, args) => {
            if (args.status === 403) {
                location.reload();
            }
        });
        this._store.AddPathHandler('security.settings', (data) => {
            if (!data.logged) {
                this.LoginForm.Show();
            }
        });


        console.log('Initializing module Security');

        App.AddHandler('ApplicationReady', (event, args) => {
            this.Render(document.body);
            this.Settings();
        });

        App.Router.AddRoutePattern('/logout/', (url, options) => {
            this.Logout();
            App.Router.Navigate('', {});
        });

        Colibri.Common.StartTimer('security-ping', 10 * 60 * 1000, () => {
            this.Ping();
        });


    }

    Render(container) {
        console.log('Rendering Module Security');


    }

    RegisterEvents() {
        console.log('Registering module events for Security');


    }

    RegisterEventHandlers() {
        console.log('Registering event handlers for Security');


    }

    ShowProfileWindow() {
        if (this.IsCommandAllowed('security.profile')) {
            Manage.FormWindow.Show('#{security-userprofile}', 800, 'app.manage.storages(name=users,module=security)', this._store.Query('security.user'), '', {}, (data) => {
                App.Loading.Show();
                this.SaveUser(data).then(() => {
                    Manage.FormWindow.Hide();
                }).finally(() => {
                    App.Loading.Hide();
                });
            }, () => {
                Manage.FormWindow.Hide();
            });
        }
        else {
            App.Notices.Add(new Colibri.UI.Notice('#{security-global-notallowed}', Colibri.UI.Notice.Error, 5000));
        }
    }

    Menu(isadmin) {

        const userData = this._store.Query('security.user');

        let profile = [];
        profile.push({ title: userData.fio.firstName + ' ' + userData.fio.lastName, route: '' });
        profile.push({ title: '#{security-menu-userprofile}', route: '/app/more/security/profile/', icon: Colibri.UI.LkIcon, });
        if (isadmin) {
            profile.push({ title: '#{security-menu-admin}', route: '/app/more/security/users/', icon: Colibri.UI.AdministrationIcon, });
        }

        let menu = {
            profile: profile
        };

        this._store.Set('security.menu', menu);
    }

    InitComet() {
        const userData = this._store.Query('security.user');
        App.Comet && App.Comet.Init({ guid: String.MD5(userData.id + ''), name: userData.fio.lastName + ' ' + userData.fio.firstName }, App.Store, 'app.messages');
    }

    Settings(returnPromise = false) {
        const promise = this.Call('Client', 'Settings')
        if (returnPromise) {
            return promise;
        }

        promise.then((response) => {
            this._store.Set('security.settings', response.result.settings);
            this._store.Set('security.user', response.result.user);
            this.Menu(false);
            this.InitComet();
        }).catch((response) => {
            App.Notices && App.Notices.Add({
                severity: 'error',
                title: response.result,
                timeout: 5000
            });
        });
    }

    Roles(returnPromise = false) {
        const promise = this.Call('Client', 'Roles')
        if (returnPromise) {
            return promise;
        }

        promise.then((response) => {
            this._store.Set('security.roles', response.result);
        }).catch((response) => {
            App.Notices && App.Notices.Add({
                severity: 'error',
                title: response.result,
                timeout: 5000
            });
        });
    }

    Users(returnPromise = false) {
        const promise = this.Call('Client', 'Users')
        if (returnPromise) {
            return promise;
        }

        promise.then((response) => {
            this._store.Set('security.users', response.result);
        }).catch((response) => {
            App.Notices && App.Notices.Add({
                severity: 'error',
                title: response.result,
                timeout: 5000
            });
        });
    }


    Ping() {
        this.Call('Client', 'Ping', {});
    }

    Login(login, password) {
        this.Call('Client', 'Login', { login: login, password: password })
            .then((response) => {
                App.Notices.Add(new Colibri.UI.Notice('#{security-login-success-message}', Colibri.UI.Notice.Success, 3000));
                Colibri.Common.Delay(3000).then(() => {
                    location.reload();
                });
            })
            .catch(error => {
                App.Notices.Add(new Colibri.UI.Notice('#{security-login-error-message}'));
                console.error(error);
            });

    }

    Logout(noreload) {
        this.Call('Client', 'Logout')
            .then((response) => {
                App.Notices.Add(new Colibri.UI.Notice('#{security-logout-success-message}', Colibri.UI.Notice.Success, 3000));
                Colibri.Common.Delay(3000).then(() => {
                    location.reload();
                });

            })
            .catch(error => {
                App.Notices.Add(new Colibri.UI.Notice(error.result));
                console.error(error);
            });
    }

    Register(value) {
        this.Call('Client', 'Register', value)
            .then((response) => {
                App.Notices.Add(new Colibri.UI.Notice('#{security-register-success-message}', Colibri.UI.Notice.Success, 3000));
                Colibri.Common.Delay(3000).then(() => {
                    location.reload();
                });
            })
            .catch(error => {
                App.Notices.Add(new Colibri.UI.Notice(error.result));
                console.error(error);
            });
    }

    SaveUser(value) {
        return new Promise((resolve, reject) => {

            this.Call('Client', 'SaveUser', value)
                .then((response) => {
                    const currentUser = this._store.Query('security.user');
                    const savedUser = response.result;
                    if (savedUser.id == currentUser.id) {
                        this._store.Set('security.user', response.result);
                    }

                    let users = this._store.Query('security.users');
                    if (!Array.isArray(users)) {
                        users = [];
                    }

                    let isAdd = true;
                    users = users.map((u) => {
                        if (u.id == savedUser.id) {
                            isAdd = false;
                            return savedUser;
                        }
                        else {
                            return u;
                        }
                    });
                    if (isAdd) {
                        users.push(savedUser);
                    }
                    this._store.Set('security.users', users);

                    App.Notices.Add(new Colibri.UI.Notice('#{security-messages-datasaved}', Colibri.UI.Notice.Success, 3000));
                    resolve(response.result);
                })
                .catch(error => {
                    App.Notices.Add(new Colibri.UI.Notice(error.result));
                    console.error(error);
                    reject(error.result);
                });
        });
    }

    SaveRole(value) {
        this.Call('Client', 'SaveRole', value)
            .then((response) => {
                const role = response.result;
                let roles = this._store.Query('security.roles');
                let isAdd = true;
                roles = roles.map((r) => {
                    if (r.id == role.id) {
                        isAdd = false;
                        return role;
                    }
                    else {
                        return r;
                    }
                });
                if (isAdd) {
                    roles.push(role);
                }
                this._store.Set('security.roles', roles);
                this._store.DispatchPath('security.users');
                App.Notices.Add(new Colibri.UI.Notice('#{security-messages-datasaved}', Colibri.UI.Notice.Success, 3000));
            })
            .catch(error => {
                App.Notices.Add(new Colibri.UI.Notice(error.result));
                console.error(error);
            });
    }

    RemoveRole(value) {
        this.Call('Client', 'RemoveRole', value)
            .then((response) => {
                let roles = this._store.Query('security.roles');
                let newRoles = [];
                roles.map((r) => {
                    if (r.id != value.id) {
                        newRoles.push(r);
                    }
                });
                this._store.Set('security.roles', newRoles);
                this._store.Reload('security.users', false);
                App.Notices.Add(new Colibri.UI.Notice('#{security-messages-dataremoved}', Colibri.UI.Notice.Success, 3000));
            })
            .catch(error => {
                App.Notices.Add(new Colibri.UI.Notice(error.result));
                console.error(error);
            });
    }

    RemoveUser(value) {
        this.Call('Client', 'RemoveUser', value)
            .then((response) => {
                let users = this._store.Query('security.users');
                if (!Array.isArray(users)) {
                    users = [];
                }

                let newUsers = [];
                users.map((u) => {
                    if (u.id != value.id) {
                        newUsers.push(u);
                    }
                });

                this._store.Set('security.users', newUsers);
                App.Notices.Add(new Colibri.UI.Notice('#{security-messages-dataremoved}', Colibri.UI.Notice.Success, 3000));
            })
            .catch(error => {
                App.Notices.Add(new Colibri.UI.Notice(error.result));
                console.error(error);
            });
    }

    ResetRequest(value) {
        this.Call('Client', 'ResetRequest', value)
            .then((response) => {
                App.Notices.Add(new Colibri.UI.Notice('#{security-reset-message}', Colibri.UI.Notice.Success, 3000));
                Colibri.Common.Delay(3000).then(() => {
                    location.reload();
                });
            })
            .catch(error => {
                App.Notices.Add(new Colibri.UI.Notice(error.result));
                console.error(error);
            });
    }


    get LoginForm() {
        if (this._loginForm) {
            return this._loginForm;
        }

        this._loginForm = new App.Modules.Security.Login('login-form', document.body);
        if (!this._loginForm.isConnected) {
            this._loginForm.ConnectTo(document.body);
        }

        return this._loginForm;
    }


    get Store() {
        return this._store;
    }

    GetUserPermissions(userOrRole = null) {

        let perms = [];
        if (!userOrRole || userOrRole.role !== undefined) {
            const user = userOrRole || this._store.Query('security.user');
            const role = user.role;

            const userPermissions = user.permissions;
            const rolePermissions = role.permissions;

            perms = rolePermissions.concat(userPermissions);
        }
        else {
            perms = userOrRole.permissions;
        }

        perms.sort((a, b) => {
            if (a.path > b.path) {
                return -1;
            }
            else if (a.path < b.path) {
                return 1;
            }
            return 0;
        });
        return perms;
    }

    IsCommandSet(command, userOrRole = null) {
        const perms = this.GetUserPermissions(userOrRole);

        for (const perm of perms) {
            if (command == perm.path) {
                return perm.value;
            }
        }

        return null;
    }

    IsCommandAllowed(command, userOrRole = null) {
        // реализовать проверку

        let isNot = false;
        if (command.substr(0, 1) == '!') {
            isNot = true;
            command = command.substr(1);
        }

        const perms = this.GetUserPermissions(userOrRole);

        for (const perm of perms) {
            const reg = new RegExp(perm.path.replace(/\./, '\.').replace(/\*/, '.*'), 'im');
            if (reg.test(command) !== false) {
                return isNot ? perm.value !== 'allow' : perm.value === 'allow';
            }
        }

        return isNot ? true : false;

    }

    RemovePermission(perms, perm) {
        let found = -1;
        perms.forEach((p, i) => {
            if (p.path == perm) {
                found = i;
                return false;
            }
            return true;
        });
        perms.splice(found, 1);
        return perms;
    }

    AddPermission(perms, perm, acc) {
        if (!Array.isArray(perms)) {
            perms = [];
        }
        perms.push({ path: perm, value: acc });
        return perms;
    }



}

